    for (int i = 0; i < 8; ++i) {
      // up barrier
      double lowerBarrier = 1.1 + 0.025 * i;
      SimpleConstantContinuousBarrier dko =
          SimpleConstantContinuousBarrier.of(BarrierType.DOWN, KnockType.KNOCK_OUT, lowerBarrier);
