    FxEuropeanOptionTradeCalculationFunction function = new FxEuropeanOptionTradeCalculationFunction();
    ScenarioMarketData md = marketData();
    RatesProvider provider = RATES_LOOKUP.ratesProvider(md.scenario(0));
