    double expectedDelta = pricer.delta(RTRADE, provider, VOLS);
    CurrencyAmount expectedCash = pricer.currentCash(RTRADE, VAL_DATE);

    Set<Measure> measures = ImmutableSet.of(
        Measures.PRESENT_VALUE,
