  @Test
  public void test_load_fx_ndf() {
    TradeCsvLoader standard = TradeCsvLoader.standard();
    ResourceLocator locator = ResourceLocator.of("classpath:com/opengamma/strata/loader/csv/fxtrades2.csv");
