/**
 * Multi-scenario measure calculations for FX vanilla option trades.
 * <p>
 * Each method corresponds to a measure, typically calculated by one or more calls to the pricer.
 */
final class FxEuropeanOptionMeasureCalculations {

  /**
   * Default implementation.
   */
  public static final FxEuropeanOptionMeasureCalculations DEFAULT = new FxEuropeanOptionMeasureCalculations(
      BlackFxEuropeanOptionTradePricer.DEFAULT,
      VannaVolgaFxEuropeanOptionTradePricer.DEFAULT);
  /**
   * The market quote sensitivity calculator.
   */
  private static final MarketQuoteSensitivityCalculator MARKET_QUOTE_SENS = MarketQuoteSensitivityCalculator.DEFAULT;
  /**
   * One basis point, expressed as a {@code double}.
   */
  private static final double ONE_BASIS_POINT = 1e-4;

  /**
   * Pricer for {@link ResolvedFxEuropeanOptionTrade}.
   */
  private final BlackFxEuropeanOptionTradePricer blackPricer;
  /**
   * Pricer for {@link ResolvedFxEuropeanOptionTrade}.
   */
  private final VannaVolgaFxEuropeanOptionTradePricer vannaVolgaPricer;

  /**
   * Creates an instance.
   * 
   * @param blackPricer  the pricer for {@link ResolvedFxEuropeanOptionTrade} using Black
   * @param vannaVolgaPricer  the pricer for {@link ResolvedFxEuropeanOptionTrade} using Vanna-Volga
   */
  FxEuropeanOptionMeasureCalculations(
      BlackFxEuropeanOptionTradePricer blackPricer,
      VannaVolgaFxEuropeanOptionTradePricer vannaVolgaPricer) {
    this.blackPricer = ArgChecker.notNull(blackPricer, "blackPricer");
    this.vannaVolgaPricer = ArgChecker.notNull(vannaVolgaPricer, "vannaVolgaPricer");
  }

  //-------------------------------------------------------------------------
  // calculates present value for all scenarios
  MultiCurrencyScenarioArray presentValue(
      ResolvedFxEuropeanOptionTrade trade,
      RatesScenarioMarketData ratesMarketData,
      FxOptionScenarioMarketData optionMarketData,
      FxEuropeanOptionMethod method) {

    CurrencyPair currencyPair = trade.getProduct().getCurrencyPair();
    return MultiCurrencyScenarioArray.of(
        ratesMarketData.getScenarioCount(),
        i -> presentValue(
            trade,
            ratesMarketData.scenario(i).ratesProvider(),
            optionMarketData.scenario(i).volatilities(currencyPair),
            method));
  }

  // present value for one scenario
  MultiCurrencyAmount presentValue(
      ResolvedFxEuropeanOptionTrade trade,
      RatesProvider ratesProvider,
      FxOptionVolatilities volatilities,
      FxEuropeanOptionMethod method) {

    if (method == FxEuropeanOptionMethod.VANNA_VOLGA) {
      return vannaVolgaPricer.presentValue(trade, ratesProvider, checkVannaVolgaVolatilities(volatilities));
    } else {
      return blackPricer.presentValue(trade, ratesProvider, checkBlackVolatilities(volatilities));
    }
  }

  //-------------------------------------------------------------------------
  // calculates calibrated sum PV01 for all scenarios
  MultiCurrencyScenarioArray pv01RatesCalibratedSum(
      ResolvedFxEuropeanOptionTrade trade,
      RatesScenarioMarketData ratesMarketData,
      FxOptionScenarioMarketData optionMarketData,
      FxEuropeanOptionMethod method) {

    CurrencyPair currencyPair = trade.getProduct().getCurrencyPair();
    return MultiCurrencyScenarioArray.of(
        ratesMarketData.getScenarioCount(),
